import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.BaLY0aY1.js";const h=JSON.parse('{"title":"Validation","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/validation.md","filePath":"implementation/validation.md","lastUpdated":1779877197000}'),o={name:"implementation/validation.md"};function n(l,e,d,s,u,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h1><p>TORCH validates CRTDL definitions before starting data extraction.</p><p>The goal of validation is to detect invalid extraction definitions early and to transform the input CRTDL into an annotated representation that can be processed consistently during extraction.</p><p>Validation in TORCH covers both:</p><ul><li>structural checks of the CRTDL</li><li>annotation of attribute groups and attributes for downstream processing</li></ul><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>During validation, TORCH:</p><ul><li>resolves the referenced profiles of all attribute groups</li><li>ensures that exactly one <code>Patient</code> attribute group exists</li><li>validates that all referenced attributes exist in the corresponding profile</li><li>validates linking rules for reference attributes</li><li>validates that all linked groups are defined</li><li>extracts consent codes from the CRTDL</li><li>enriches attribute groups with standard attributes required for processing</li></ul><p>The result of validation is an <code>AnnotatedCrtdl</code>.</p><h2 id="validation-rules" tabindex="-1">Validation Rules <a class="header-anchor" href="#validation-rules" aria-label="Permalink to &quot;Validation Rules&quot;">​</a></h2><h3 id="known-profiles" tabindex="-1">Known profiles <a class="header-anchor" href="#known-profiles" aria-label="Permalink to &quot;Known profiles&quot;">​</a></h3><p>Each attribute group must reference a known profile via <code>groupReference</code>.</p><p>If TORCH cannot resolve the referenced profile, validation fails.</p><h3 id="exactly-one-patient-attribute-group" tabindex="-1">Exactly one Patient attribute group <a class="header-anchor" href="#exactly-one-patient-attribute-group" aria-label="Permalink to &quot;Exactly one Patient attribute group&quot;">​</a></h3><p>A valid CRTDL must contain exactly one attribute group whose referenced profile has resource type <code>Patient</code>.</p><p>Validation fails if:</p><ul><li>no patient attribute group exists</li><li>more than one patient attribute group exists</li></ul><p>This patient group is also used when generating standard patient reference attributes for other groups.</p><h3 id="known-attributes" tabindex="-1">Known attributes <a class="header-anchor" href="#known-attributes" aria-label="Permalink to &quot;Known attributes&quot;">​</a></h3><p>Each attribute in an attribute group must reference an element that exists in the corresponding profile.</p><p>If an attribute reference cannot be resolved in the referenced profile, validation fails.</p><h3 id="typed-attributes" tabindex="-1">Typed attributes <a class="header-anchor" href="#typed-attributes" aria-label="Permalink to &quot;Typed attributes&quot;">​</a></h3><p>Each referenced element must have a type in the resolved profile definition.</p><p>Typeless attributes are rejected during validation.</p><h3 id="reference-attributes-must-declare-linked-groups" tabindex="-1">Reference attributes must declare linked groups <a class="header-anchor" href="#reference-attributes-must-declare-linked-groups" aria-label="Permalink to &quot;Reference attributes must declare linked groups&quot;">​</a></h3><p>If an attribute is a pure <code>Reference</code> attribute, it must declare at least one linked group.</p><p>Validation fails for reference attributes without linked groups.</p><h3 id="linked-groups-must-exist" tabindex="-1">Linked groups must exist <a class="header-anchor" href="#linked-groups-must-exist" aria-label="Permalink to &quot;Linked groups must exist&quot;">​</a></h3><p>TORCH collects all linked group ids used by attributes and checks that all of them correspond to defined attribute groups.</p><p>Validation fails if linked groups are referenced but no matching attribute group exists.</p><h3 id="consent-validation" tabindex="-1">Consent validation <a class="header-anchor" href="#consent-validation" aria-label="Permalink to &quot;Consent validation&quot;">​</a></h3><p>During validation, TORCH extracts consent codes from the CRTDL.</p><p>If the consent definition is malformed, validation fails with a consent-related validation error.</p><h2 id="annotation-of-attributes" tabindex="-1">Annotation of Attributes <a class="header-anchor" href="#annotation-of-attributes" aria-label="Permalink to &quot;Annotation of Attributes&quot;">​</a></h2><p>After validation, user-defined attributes are converted into annotated attributes.</p><p>For each declared attribute, TORCH creates an annotated representation containing:</p><ul><li>the original <code>attributeRef</code></li><li>the resolved FHIRPath used internally for processing</li><li>the <code>mustHave</code> flag</li><li>the configured <code>linkedGroups</code></li></ul><p>This means validation does not only check correctness, but also prepares the CRTDL for later extraction steps.</p><h2 id="standard-attributes-added-during-validation" tabindex="-1">Standard Attributes Added During Validation <a class="header-anchor" href="#standard-attributes-added-during-validation" aria-label="Permalink to &quot;Standard Attributes Added During Validation&quot;">​</a></h2><p>In addition to the explicitly defined CRTDL attributes, TORCH automatically adds a small set of standard attributes to each attribute group.</p><p>These attributes are generated during validation and do not need to be specified manually in the CRTDL.</p><h3 id="added-for-all-attribute-groups" tabindex="-1">Added for all attribute groups <a class="header-anchor" href="#added-for-all-attribute-groups" aria-label="Permalink to &quot;Added for all attribute groups&quot;">​</a></h3><p>For every attribute group, TORCH adds:</p><ul><li><code>&lt;ResourceType&gt;.id</code></li><li><code>&lt;ResourceType&gt;.meta.profile</code></li></ul><p>These attributes are required for technical processing and profile-aware handling.</p><h3 id="added-for-patient-groups" tabindex="-1">Added for Patient groups <a class="header-anchor" href="#added-for-patient-groups" aria-label="Permalink to &quot;Added for Patient groups&quot;">​</a></h3><p>If the attribute group references the resource type <code>Patient</code>, TORCH additionally adds:</p><ul><li><code>Patient.identifier</code></li></ul><h3 id="added-for-resources-in-the-patient-compartment" tabindex="-1">Added for resources in the patient compartment <a class="header-anchor" href="#added-for-resources-in-the-patient-compartment" aria-label="Permalink to &quot;Added for resources in the patient compartment&quot;">​</a></h3><p>If the resource type belongs to the patient compartment, TORCH checks whether the referenced profile contains the following elements:</p><ul><li><code>&lt;ResourceType&gt;.patient</code></li><li><code>&lt;ResourceType&gt;.subject</code></li></ul><p>If present, these attributes are added automatically.</p><p>These generated patient reference attributes are linked to the patient attribute group in order to preserve the relation between the resource and the patient.</p><h3 id="summary-of-generated-standard-attributes" tabindex="-1">Summary of generated standard attributes <a class="header-anchor" href="#summary-of-generated-standard-attributes" aria-label="Permalink to &quot;Summary of generated standard attributes&quot;">​</a></h3><p>Depending on the resource type, validation may add:</p><ul><li>always: <ul><li><code>&lt;ResourceType&gt;.id</code></li><li><code>&lt;ResourceType&gt;.meta.profile</code></li></ul></li><li>for <code>Patient</code>: <ul><li><code>Patient.identifier</code></li></ul></li><li>for patient-compartment resources, if present in the profile: <ul><li><code>&lt;ResourceType&gt;.patient</code></li><li><code>&lt;ResourceType&gt;.subject</code></li></ul></li></ul><h2 id="result-of-validation" tabindex="-1">Result of Validation <a class="header-anchor" href="#result-of-validation" aria-label="Permalink to &quot;Result of Validation&quot;">​</a></h2><p>If validation succeeds, TORCH returns an <code>AnnotatedCrtdl</code> containing:</p><ul><li>the original cohort definition</li><li>annotated attribute groups</li><li>extracted consent codes, if present</li></ul><p>Each annotated attribute group contains:</p><ul><li>group metadata such as name, id, resource type, and group reference</li><li>generated standard attributes</li><li>validated and annotated user-defined attributes</li><li>the original filters</li><li>the original <code>includeReferenceOnly</code> setting</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><p>Validation in TORCH is not limited to rejecting invalid input. It also performs normalization and enrichment needed for extraction.</p><p>In particular, validation ensures that downstream processing can rely on:</p><ul><li>resolved profiles</li><li>resolved attribute definitions</li><li>explicit linked-group information</li><li>standard technical attributes such as <code>id</code> and <code>meta.profile</code></li><li>patient reference fields where needed for referential integrity</li></ul>',65)])])}const f=t(o,[["render",n]]);export{h as __pageData,f as default};
